# -*- coding: utf-8 -*-
"""构建 Ikarao 美亚增长分析 交互HTML(单文件自包含)。
读取 asin_monthly.csv, store_monthly.csv, sqp_keywords.json -> 输出 html。"""
import csv, json, os, glob

S = r"C:\Users\EDY\AppData\Local\Temp\claude\D--nexgaios-amazon\c2447dd3-2349-4cf9-9a0a-6412699591c5\scratchpad"
OUT_HTML = r"D:\nexgaios-amazon\ikarao-us-growth-analysis.html"
FX = 7.1043
TARGET_LO_CNY, TARGET_HI_CNY = 1.95e8, 2.10e8

MONTHS = [f"2025-{m:02d}" for m in range(1,13)] + [f"2026-{m:02d}" for m in range(1,7)]

META = {
 "B0CR1R7FKP": {"model":"1030 · Break X2","series":"Break","price":449.99,"short":"主力爆款 · 300W · 4个DJ灯 · 32GB","color":"#2563eb"},
 "B0CLLT85Y6": {"model":"1032 · Break X1","series":"Break","price":699.99,"short":"旗舰 · 13.3\"大屏 · 800W","color":"#7c3aed"},
 "B0DCZQX11P": {"model":"1002 · Shell S1","series":"Shell","price":399.99,"short":"10.1\"屏 · 280W · HDMI","color":"#059669"},
 "B0DHPN1DMJ": {"model":"1004 · Shell S2","series":"Shell","price":349.99,"short":"便携 · 140W · 连TV","color":"#d97706"},
 "B0FNCQW2K3": {"model":"1035 · Shell S3","series":"Shell","price":249.99,"short":"新品入门 · 32GB","color":"#db2777"},
}
ASIN_ORDER = ["B0CR1R7FKP","B0CLLT85Y6","B0DCZQX11P","B0DHPN1DMJ","B0FNCQW2K3"]

def fnum(x):
    if x is None: return None
    x = str(x).strip()
    if x=="" or x.lower()=="none": return None
    try: return float(x)
    except: return None

# ---------- 载入 asin_monthly(合并所有 rows_*.jsonl) ----------
def load_asin():
    rows={}
    for fn in glob.glob(os.path.join(S,"rows_*.jsonl")):
        for line in open(fn,encoding="utf-8"):
            line=line.strip()
            if not line: continue
            r=json.loads(line)
            rows[(r["month"],r["asin"])]=r
    return rows

def load_store():
    d={}; o={}
    for r in csv.DictReader(open(os.path.join(S,"store_monthly.csv"),encoding="utf-8-sig")):
        d[r["month"]]=fnum(r["store_sales_usd"])
        o[r["month"]]=fnum(r["store_orders"])
    return d,o

def series(rows, asin, field, deriv=None):
    out=[]
    for m in MONTHS:
        r=rows.get((m,asin))
        if r is None: out.append(None); continue
        if deriv=="asp":
            amt=fnum(r.get("amount")); vol=fnum(r.get("volume"))
            out.append(round(amt/vol,2) if amt and vol else None)
        elif deriv=="promo_share":
            pa=fnum(r.get("promotion_amount")); amt=fnum(r.get("amount"))
            out.append(round(pa/amt,4) if pa is not None and amt else 0.0)
        else:
            out.append(fnum(r.get(field)))
    return out

def yoy(vals):
    """2026 各月 vs 2025 同月;返回长度18,前6(2025 H1)为None占位, 2025 H2->None, 2026->pct"""
    out=[None]*18
    for i,m in enumerate(MONTHS):
        if m.startswith("2026"):
            pm="2025"+m[4:]
            j=MONTHS.index(pm)
            a=vals[i]; b=vals[j]
            out[i]=round((a/b-1)*100,1) if (a is not None and b) else None
    return out

def mom(vals):
    out=[None]
    for i in range(1,len(vals)):
        a=vals[i]; b=vals[i-1]
        out.append(round((a/b-1)*100,1) if (a is not None and b) else None)
    return out

def main():
    rows=load_asin()
    store,orders=load_store()

    # 每 ASIN 各指标 series
    FIELDS = {
      "amount":("amount",None),"volume":("volume",None),"asp":(None,"asp"),
      "sessions":("sessions_total",None),"cvr":("cvr",None),"adv_rate":("adv_rate",None),
      "tacos":("tacos",None),"acos":("acos",None),"return_rate":("return_goods_rate",None),
      "promo_share":(None,"promo_share"),"rank_k":("rank_karaoke",None),
      "reviews":("reviews_count",None),"star":("avg_star",None),"bb":("buy_box_percentage",None),
      "spend":("spend",None),"ad_sales":("ad_sales_amount",None),"impressions":("impressions",None),
    }
    asins=[]
    for a in ASIN_ORDER:
        s={}
        for k,(f,d) in FIELDS.items():
            s[k]=series(rows,a,f,d)
        # 首个活跃月
        first=None
        for i,v in enumerate(s["volume"]):
            if v: first=MONTHS[i]; break
        asins.append({"asin":a,**META[a],"s":s,"first":first})

    # 品牌合计(5 ASIN)
    def sum_series(field_key):
        out=[]
        for i in range(18):
            vals=[x["s"][field_key][i] for x in asins if x["s"][field_key][i] is not None]
            out.append(round(sum(vals),2) if vals else None)
        return out
    brand={"amount":sum_series("amount"),"volume":sum_series("volume"),
           "sessions":sum_series("sessions"),"spend":sum_series("spend"),
           "ad_sales":sum_series("ad_sales")}
    brand["asp"]=[round(brand["amount"][i]/brand["volume"][i],2) if brand["volume"][i] else None for i in range(18)]
    brand["adv_rate"]=[round(brand["ad_sales"][i]/brand["amount"][i],4) if brand["amount"][i] else None for i in range(18)]

    store_s=[store.get(m) for m in MONTHS]
    store_o=[orders.get(m) for m in MONTHS]

    # ---------- KPI / 目标 ----------
    def hsum(vals,yr,h):
        idx=[MONTHS.index(f"{yr}-{m:02d}") for m in (range(1,7) if h==1 else range(7,13))]
        return sum(vals[i] for i in idx if vals[i] is not None)
    h1_25=hsum(store_s,2025,1); h2_25=hsum(store_s,2025,2); fy25=h1_25+h2_25; h1_26=hsum(store_s,2026,1)
    o_h1_25=hsum(store_o,2025,1); o_h1_26=hsum(store_o,2026,1)
    share_h1=h1_25/fy25
    proj_fy26=h1_26/share_h1
    tlo,thi=TARGET_LO_CNY/FX, TARGET_HI_CNY/FX
    kpi={
      "h1_25":h1_25,"h1_26":h1_26,"h1_yoy":round((h1_26/h1_25-1)*100,1),
      "o_h1_25":o_h1_25,"o_h1_26":o_h1_26,"o_yoy":round((o_h1_26/o_h1_25-1)*100,1),
      "aov_25":round(h1_25/o_h1_25,1),"aov_26":round(h1_26/o_h1_26,1),
      "aov_yoy":round((h1_26/o_h1_26)/(h1_25/o_h1_25)*100-100,1),
      "fy25":fy25,"h2_25":h2_25,"share_h1":round(share_h1*100,1),
      "q4_share":round((store["2025-11"]+store["2025-12"])/fy25*100,1),
      "proj_fy26":proj_fy26,"tlo":tlo,"thi":thi,
      "gap_lo":proj_fy26-tlo,"gap_hi":proj_fy26-thi,
      "req_yoy_lo":round((tlo/fy25-1)*100),"req_yoy_hi":round((thi/fy25-1)*100),
      "h2_need_lo":tlo-h1_26,"h2_need_hi":thi-h1_26,
      "h2_yoy_lo":round((tlo-h1_26)/h2_25*100-100),"h2_yoy_hi":round((thi-h1_26)/h2_25*100-100),
      "fx":FX,"tlo_cny":TARGET_LO_CNY,"thi_cny":TARGET_HI_CNY,
    }

    # ---------- 异常检测 ----------
    def mean(xs): xs=[x for x in xs if x is not None]; return sum(xs)/len(xs) if xs else None
    def recent(sr): return mean(sr[-3:])  # 2026-04..06
    peer_cvr=mean([recent(x["s"]["cvr"]) for x in asins if x["asin"]!="B0FNCQW2K3"])
    anomalies=[]
    for x in asins:
        a=x["asin"]; m=x["model"]; s=x["s"]
        vol_h1_25=hsum(s["volume"],2025,1); vol_h1_26=hsum(s["volume"],2026,1)
        amt_h1_25=hsum(s["amount"],2025,1); amt_h1_26=hsum(s["amount"],2026,1)
        def add(dr,sev,title,ev,hyp):
            anomalies.append({"asin":a,"model":m,"dir":dr,"sev":sev,"title":title,"ev":ev,"hyp":hyp})
        if a!="B0FNCQW2K3" and vol_h1_25>0:
            vy=(vol_h1_26/vol_h1_25-1)*100; ay=(amt_h1_26/amt_h1_25-1)*100
            if vy<=-5:
                add("坏","高" if vy<=-12 else "中","销量同比下滑 %.0f%%"%vy,
                    "H1销量 %d→%d(同比%.0f%%),销售额同比%.0f%%"%(vol_h1_25,vol_h1_26,vy,ay),
                    "涨价+品类价格战下,老品在以价换量地萎缩;靠涨价撑住销售额,单量却在流失。")
            elif vy>=12:
                add("好","高" if vy>=20 else "中","销量同比增长 %.0f%%"%vy,
                    "H1销量 %d→%d(同比+%.0f%%),销售额同比%.0f%%"%(vol_h1_25,vol_h1_26,vy,ay),
                    "该款是当前增长主引擎,值得加大流量/库存投入放大。")
        rr=recent(s["return_rate"])
        if rr and rr>=0.10:
            add("坏","高" if rr>=0.13 else "中","退货率偏高 %.1f%%"%(rr*100),
                "近3月平均退货率 %.1f%%"%(rr*100),
                "高退货吞噬利润且影响权重/评分;需查退货原因(质量/预期落差/物流),对症降退货。")
        adv=recent(s["adv_rate"])
        if adv and adv>=0.82:
            add("坏","高" if adv>=0.90 else "中","广告依赖过高 %.0f%%"%(adv*100),
                "近3月广告销售占比 %.0f%%,自然单占比仅 %.0f%%"%(adv*100,(1-adv)*100),
                "自然位薄弱、几乎全靠付费买量;广告一停就掉,增长不健康,需夯实自然排名/评论。")
        tac=recent(s["tacos"])
        if tac and tac>=0.13:
            add("坏","中","TACOS 偏高 %.1f%%"%(tac*100),
                "近3月 TACOS %.1f%%"%(tac*100),"广告效率偏低,吃掉本已被内存成本压薄的利润。")
        ps=recent(s["promo_share"])
        if ps and ps>=0.28:
            add("坏","高" if ps>=0.38 else "中","促销依赖高 %.0f%%"%(ps*100),
                "近3月促销金额占营收 %.0f%%"%(ps*100),
                "销量靠大额促销撑,实际到手价被拉低,与'涨价'方向相悖,利润受双重挤压。")
        cvr=recent(s["cvr"])
        if cvr and peer_cvr and cvr<0.72*peer_cvr:
            add("坏","中","转化率偏低 %.1f%%"%(cvr*100),
                "近3月CVR %.1f%% vs 同组均 %.1f%%"%(cvr*100,peer_cvr*100),
                "流量与转化不匹配:可能价格锚点、主图/评分或流量精准度问题,是可撬动的转化增量点。")
        elif cvr and peer_cvr and cvr>1.3*peer_cvr:
            add("好","中","转化率领先 %.1f%%"%(cvr*100),
                "近3月CVR %.1f%% vs 同组均 %.1f%%"%(cvr*100,peer_cvr*100),
                "转化效率高,加大曝光的边际产出好,适合放量。")
        # 排名
        rk=[ (MONTHS[i],s["rank_k"][i]) for i in range(18) if s["rank_k"][i] is not None]
        if len(rk)>=2:
            r_first=rk[0][1]; r_last=rk[-1][1]
            if r_last<=3 and a!="B0FNCQW2K3":
                add("好","中","小类目稳居 Top%d"%int(r_last),
                    "Karaoke Portable Systems 排名 %s:%d → %s:%d"%(rk[0][0],r_first,rk[-1][0],r_last),
                    "头部位置=稳定自然流量,是守住基本盘的资产。")
    # 新品 1035 ramp
    x35=[x for x in asins if x["asin"]=="B0FNCQW2K3"][0]
    v35=[v for v in x35["s"]["volume"] if v]
    if v35:
        anomalies.append({"asin":"B0FNCQW2K3","model":"1035 · Shell S3","dir":"好","sev":"高",
            "title":"新品从0起量","ev":"上市数月即达月销 ~%d 台($250价位带)"%int(x35["s"]["volume"][-1] or 0),
            "hyp":"填补了 Ikarao 缺失的中低价位带,是当前最大的纯增量来源;但客单/利润低,需平衡GMV与利润。"})
    # 排序:坏在前,按严重度
    sevrank={"高":0,"中":1,"关注":2}; dirrank={"坏":0,"好":1}
    anomalies.sort(key=lambda z:(dirrank.get(z["dir"],2),sevrank.get(z["sev"],3)))

    sqp=json.load(open(os.path.join(S,"sqp_keywords.json"),encoding="utf-8"))

    data={"months":MONTHS,"asins":asins,"brand":brand,"store":{"sales":store_s,"orders":store_o},
          "kpi":kpi,"anomalies":anomalies,"sqp":sqp,"meta":{k:META[k] for k in META},"order":ASIN_ORDER}

    html=TEMPLATE.replace("/*__DATA__*/", json.dumps(data,ensure_ascii=False))
    with open(OUT_HTML,"w",encoding="utf-8") as f: f.write(html)
    print("写出:",OUT_HTML,"大小KB:",round(os.path.getsize(OUT_HTML)/1024,1))
    # 打印KPI核对
    print("H1 YoY %.1f%% | 订单YoY %.1f%% | AOV %.0f->%.0f (%.1f%%)"%(kpi["h1_yoy"],kpi["o_yoy"],kpi["aov_25"],kpi["aov_26"],kpi["aov_yoy"]))
    print("FY25 $%.2fM | 外推FY26 $%.2fM | 目标 $%.2f-%.2fM | 缺口 $%.2f~%.2fM"%(fy25/1e6,proj_fy26/1e6,tlo/1e6,thi/1e6,kpi["gap_lo"]/1e6,kpi["gap_hi"]/1e6))
    print("异常条数:",len(anomalies))
    for z in anomalies: print("  [%s/%s] %s - %s"%(z["dir"],z["sev"],z["model"],z["title"]))

TEMPLATE = r"""<!doctype html><html lang="zh-CN"><head><meta charset="utf-8">
<meta name="viewport" content="width=device-width,initial-scale=1">
<title>Ikarao 美亚增长分析</title>
<style>
:root{--bg:#f6f7f9;--card:#fff;--ink:#0f172a;--mut:#64748b;--line:#e2e8f0;--blue:#2563eb;--good:#059669;--bad:#dc2626;--warn:#d97706;}
*{box-sizing:border-box}
body{margin:0;font-family:-apple-system,"Segoe UI","Microsoft YaHei",sans-serif;background:var(--bg);color:var(--ink);font-size:14px;line-height:1.5}
.wrap{max-width:1180px;margin:0 auto;padding:18px}
h1{font-size:20px;margin:0 0 2px}
h2{font-size:16px;margin:22px 0 10px;padding-left:9px;border-left:4px solid var(--blue)}
h3{font-size:14px;margin:14px 0 8px;color:var(--mut)}
.sub{color:var(--mut);font-size:12px}
.tabs{display:flex;gap:4px;flex-wrap:wrap;margin:14px 0;position:sticky;top:0;background:var(--bg);padding:6px 0;z-index:20}
.tab{padding:8px 14px;border-radius:8px;cursor:pointer;color:var(--mut);font-weight:600;user-select:none}
.tab.on{background:var(--ink);color:#fff}
.panel{display:none}.panel.on{display:block}
.grid{display:grid;gap:12px}
.k4{grid-template-columns:repeat(4,1fr)}.k3{grid-template-columns:repeat(3,1fr)}.k2{grid-template-columns:repeat(2,1fr)}
.card{background:var(--card);border:1px solid var(--line);border-radius:12px;padding:14px}
.kpi .lab{font-size:12px;color:var(--mut)}
.kpi .val{font-size:24px;font-weight:700;margin:3px 0}
.kpi .note{font-size:12px;color:var(--mut)}
.up{color:var(--good)}.down{color:var(--bad)}.warnc{color:var(--warn)}
.pill{display:inline-block;padding:1px 8px;border-radius:20px;font-size:11px;font-weight:700}
.pill.good{background:#dcfce7;color:#166534}.pill.bad{background:#fee2e2;color:#991b1b}.pill.watch{background:#fef3c7;color:#92400e}
.ctrls{display:flex;gap:6px;flex-wrap:wrap;align-items:center;margin:8px 0}
.btn{padding:5px 11px;border:1px solid var(--line);background:#fff;border-radius:7px;cursor:pointer;font-size:12px;color:var(--mut)}
.btn.on{background:var(--blue);color:#fff;border-color:var(--blue)}
table{border-collapse:collapse;width:100%;font-size:12.5px}
th,td{padding:6px 8px;border-bottom:1px solid var(--line);text-align:right}
th:first-child,td:first-child{text-align:left}
th{color:var(--mut);font-weight:600;cursor:pointer;white-space:nowrap}
tr:hover td{background:#f8fafc}
.tag{font-size:11px;padding:1px 6px;border-radius:4px;background:#eef2ff;color:#3730a3}
.tagb{background:#f1f5f9;color:#475569}
.chartbox{position:relative;width:100%;overflow-x:auto}
svg .gl{stroke:#eef1f5}
.tt{position:fixed;pointer-events:none;background:#0f172a;color:#fff;font-size:11px;padding:6px 8px;border-radius:6px;opacity:0;transition:opacity .08s;z-index:99;white-space:nowrap}
.lgd{display:flex;gap:12px;flex-wrap:wrap;font-size:12px;margin-top:6px}
.lgd span{display:inline-flex;align-items:center;gap:5px}.dot{width:10px;height:3px;border-radius:2px;display:inline-block}
.ins{background:#fff;border:1px solid var(--line);border-left:4px solid var(--blue);border-radius:8px;padding:10px 12px;margin:8px 0}
.ins b{color:var(--ink)}
.an{border-left:4px solid var(--bad)}.an.good{border-left-color:var(--good)}.an.watch{border-left-color:var(--warn)}
.mut{color:var(--mut)}.sm{font-size:12px}.c{text-align:center}.r{text-align:right}
.bar{height:7px;border-radius:4px;background:#e2e8f0;overflow:hidden;display:inline-block;width:60px;vertical-align:middle}
.bar>i{display:block;height:100%}
select,input{font:inherit;padding:5px 8px;border:1px solid var(--line);border-radius:7px}
