    yfmt:v=>v.toFixed(1)+'%',tfmt:v=>v.toFixed(2)+'%',zero:true}));
  // 机会词表
  const val=(a)=>a==null?'—':a;
  let ot='<thead><tr><th>关键词</th><th class="r">月搜索量</th><th class="r">曝光份</th><th class="r">购买份</th><th class="r">市场价</th><th class="r">你的价</th></tr></thead><tbody>';
  D.opportunities.slice(0,14).forEach(o=>{ot+=`<tr><td>${o.kw}</td><td>${intf(o.sv)}</td><td>${o.impr_share==null?'—':o.impr_share+'%'}</td><td>${o.purch_share==null?'0%':o.purch_share+'%'}</td><td>$${val(o.price_mkt)}</td><td>${o.price_mine==null?'—':'$'+o.price_mine}</td></tr>`;});
