  D.advantages.slice(0,14).forEach(o=>{at+=`<tr><td>${o.kw} ${o.branded?'<span class="tag">品牌</span>':'<span class="tag tagb">通用</span>'}</td><td><b>${o.purch_share}%</b></td><td>${intf(o.sv)}</td><td>${o.price_mine==null?'—':'$'+o.price_mine}</td></tr>`;});
  at+='</tbody>';document.getElementById('advtbl').innerHTML=at;
  // 核心词
  let ct='<thead><tr><th>核心词</th><th class="r">月搜索量</th><th class="r">曝光份</th><th class="r">购买份</th><th class="r">你转化</th><th class="r">市场价</th><th class="r">你的价</th><th class="r">价差</th></tr></thead><tbody>';
  D.core.forEach(c=>{const mk=c.price_mkt[li]||c.click_price_mkt[li],pm=c.price_mine[li]||c.click_price_mine[li];
    const gap=(mk&&pm)?(pm/mk).toFixed(1)+'x':'—';
    if((c.sv[li]||0)<300)return;
    ct+=`<tr><td>${c.kw}</td><td>${intf(c.sv[li])}</td><td>${c.impr_share[li]==null?'—':c.impr_share[li]+'%'}</td><td>${c.purch_share[li]==null?'—':c.purch_share[li]+'%'}</td><td>${c.conv[li]==null?'—':c.conv[li]+'%'}</td><td>${mk?'$'+mk:'—'}</td><td>${pm?'$'+pm:'—'}</td><td class="down">${gap}</td></tr>`;});
  ct+='</tbody>';document.getElementById('coretbl').innerHTML=ct;
  // 浏览器表
  buildKwTable(D,li);
  document.getElementById('kwq').oninput=e=>buildKwTable(D,li,e.target.value.toLowerCase());
}
let kwSort={k:'sv',dir:-1};
function buildKwTable(D,li,q){
  const rows=D.table.map(r=>({kw:r.kw,branded:r.branded,sv:r.sv[li],impr:r.impr_share[li],purch:r.purch_share[li],conv:r.conv[li],
     pm:r.price_mkt[li]||null,pmine:r.price_mine[li]||null})).filter(r=>!q||r.kw.toLowerCase().includes(q));
  rows.sort((a,b)=>{const x=a[kwSort.k],y=b[kwSort.k];return ((x==null?-1:x)-(y==null?-1:y))*kwSort.dir;});
  const cols=[['关键词','kw'],['搜索量','sv'],['曝光份','impr'],['购买份','purch'],['你转化','conv'],['市场价','pm'],['你的价','pmine']];
  let t='<thead><tr>'+cols.map((c,i)=>`<th class="${i?'r':''}" data-s="${c[1]}">${c[0]}</th>`).join('')+'</tr></thead><tbody>';
  rows.slice(0,120).forEach(r=>{t+=`<tr><td>${r.kw}${r.branded?' <span class="tag">品牌</span>':''}</td><td>${intf(r.sv)}</td><td>${r.impr==null?'—':r.impr+'%'}</td><td>${r.purch==null?'—':r.purch+'%'}</td><td>${r.conv==null?'—':r.conv+'%'}</td><td>${r.pm?'$'+r.pm:'—'}</td><td>${r.pmine?'$'+r.pmine:'—'}</td></tr>`;});
  t+='</tbody>';const T=document.getElementById('kwtbl');T.innerHTML=t;
  T.querySelectorAll('[data-s]').forEach(th=>th.onclick=()=>{const k=th.dataset.s;kwSort.dir=(kwSort.k==k?-kwSort.dir:-1);kwSort.k=k;buildKwTable(D,li,q);});
}

// ============ TAB 4 异常&增量 ============
function tab4(){
  const p=document.getElementById('p4'); let h='<h2>异常检测(自动标记 · 好/坏)</h2>';
