    const cl=z.dir=='好'?'good':(z.sev=='关注'?'watch':'');
    const pill=z.dir=='好'?'<span class="pill good">▲ 异常好</span>':`<span class="pill ${z.sev=='关注'?'watch':'bad'}">▼ ${z.sev=='关注'?'关注':'风险'}</span>`;
    h+=`<div class="ins an ${cl}"><div style="display:flex;justify-content:space-between"><b>${z.model} — ${z.title}</b> ${pill}</div>
      <div class="sm" style="margin-top:3px">${z.ev}</div>
      <div class="sm mut" style="margin-top:3px">→ ${z.hyp}</div></div>`;
  });
  h+='<h2>增量方向(基于以上数据)</h2>';
  const recs=[
   ['A · 守住并放大"高价护城河"','把预算与新品资源压在 <code>karaoke machine for adults</code> / premium / party 这类高价格容忍词与场景;1030 Break X2(销量YoY+22%、少促销)是主引擎,加库存+加自然位;1032 旗舰减少无谓深促、靠内容/礼赠场景撑价。','守 60% 基本盘'],
   ['B · 用 1035 有纪律地接"价格真空"','$250 的 1035 是唯一能触及 kids/mini/入门(市场价$20-60)真空的产品,是当前最大纯增量;但客单/利润低,须设促销与广告 ACOS 红线,避免拖累整体利润与品牌调性。','抢真空但控利润'],
   ['C · 堵转化漏损(曝光份≫购买份)','几乎所有通用词曝光份是购买份的2-4倍=被看到没成交。用高价锚点对比(功能/耐用/软件生态)、A+与主图强化"贵有贵的道理"、评分/评论运营,把已有曝光多转化一点,边际成本最低。','低成本要增量'],
   ['D · 修复"异常坏"的老品','1004/1002 销量同比双位数下滑+高广告依赖+高退货,是失血点:降退货(查预期落差)、重建自然位以降广告依赖、审视其价格带是否被 1035/竞品夹击并重新定位。','止血'],
   ['E · Q4 是决胜盘','H1 只占全年29%、Nov+Dec占43%。达标需 H2 同比+43~58%,常规节奏到不了。现在(7月)就得定 Q4 打法:旺季库存前置(尤其 1030/1035)、Prime Big Deal/BFCM 的选品与折扣结构、礼赠场景 listing/广告提前养词。','决定成败'],
  ];
  recs.forEach(r=>{h+=`<div class="card" style="margin:8px 0"><div style="display:flex;justify-content:space-between;align-items:baseline"><b>${r[0]}</b><span class="tag tagb">${r[2]}</span></div><div class="sm" style="margin-top:5px">${r[1]}</div></div>`;});
  h+='<div class="ins watch sm"><b>数据口径与局限:</b>销售额/销量/会话/广告均来自领星 product_performance(USD,自然月);全店销售额来自领星 StoreSales。目标按"¥3亿全球×US 65-70%÷汇率7.1043"折算,外推用2025季节性。关键词份额来自亚马逊 SQP:品牌视图=全Ikarao,ASIN视图仅 B0DHPN1DMJ(其余4款无ASIN级SQP)。SQP 缺 2025-01 与 2025 下半年,故关键词同比仅覆盖2-6月。</div>';
  p.innerHTML=h;
}

// ---------- 初始化 ----------
const TABS=[['p0','概览·结论'],['p1','品牌趋势'],['p2','ASIN透视'],['p3','关键词洞察'],['p4','异常&增量']];
const tabsEl=document.getElementById('tabs');
tabsEl.innerHTML=TABS.map((t,i)=>`<div class="tab ${i==0?'on':''}" data-i="${i}">${t[1]}</div>`).join('');
