</style></head><body><div class="wrap">
<h1>Ikarao · 美亚(香港奥卡-US)增长分析</h1>
<div class="sub" id="subttl"></div>
<div class="tabs" id="tabs"></div>
<div id="p0" class="panel on"></div>
<div id="p1" class="panel"></div>
<div id="p2" class="panel"></div>
<div id="p3" class="panel"></div>
<div id="p4" class="panel"></div>
<div class="foot" id="foot"></div>
</div>
<div class="tt" id="tt"></div>
<script>
const DATA=/*__DATA__*/;
const M=DATA.months, KPI=DATA.kpi, FX=KPI.fx;
const TT=document.getElementById('tt');
// ---------- 格式化 ----------
const money=v=>v==null?'—':(Math.abs(v)>=1e6?'$'+(v/1e6).toFixed(2)+'M':Math.abs(v)>=1e3?'$'+(v/1e3).toFixed(0)+'K':'$'+v.toFixed(0));
const cny=v=>v==null?'—':'¥'+(v*FX/1e6).toFixed(1)+'M';
const pct=(v,d=1)=>v==null?'—':(v>=0?'':'')+v.toFixed(d)+'%';
const pct100=(v,d=1)=>v==null?'—':(v*100).toFixed(d)+'%';
const intf=v=>v==null?'—':Math.round(v).toLocaleString();
const sign=v=>v==null?'':(v>=0?'+':'');
const cls=v=>v==null?'':(v>=0?'up':'down');
const mlabel=m=>m.slice(2).replace('-','/');
// ---------- SVG 折线图 ----------
function lineChart(cfg){
  // cfg:{series:[{name,color,vals,dash}], labels, yfmt, h}
  const W=Math.max(680, (cfg.labels.length*54)), H=cfg.h||240, pl=52,pr=14,pt=14,pb=26;
  let all=[]; cfg.series.forEach(s=>s.vals.forEach(v=>{if(v!=null)all.push(v)}));
  if(!all.length) all=[0,1];
  let mn=Math.min(...all,cfg.zero?0:Math.min(...all)), mx=Math.max(...all);
  if(cfg.zero)mn=Math.min(0,mn);
  if(mn===mx){mn-=1;mx+=1}
  const pad=(mx-mn)*0.12; mx+=pad; mn-=(cfg.zero&&mn>=0?0:pad*0.5); if(cfg.zero&&mn<0){}
  const x=i=>pl+i*((W-pl-pr)/(cfg.labels.length-1||1));
  const y=v=>pt+(H-pt-pb)*(1-(v-mn)/(mx-mn));
  let g=`<svg viewBox="0 0 ${W} ${H}" width="${W}" height="${H}" font-size="11">`;
  for(let t=0;t<=4;t++){const vv=mn+(mx-mn)*t/4,yy=y(vv);
    g+=`<line class="gl" x1="${pl}" y1="${yy}" x2="${W-pr}" y2="${yy}"/><text x="${pl-6}" y="${yy+3}" text-anchor="end" fill="#94a3b8">${cfg.yfmt(vv)}</text>`;}
  cfg.labels.forEach((l,i)=>{if(cfg.labels.length>13&&i%2)return;g+=`<text x="${x(i)}" y="${H-8}" text-anchor="middle" fill="#94a3b8">${l}</text>`;});
  cfg.series.forEach(s=>{
    let d='',started=false;
    s.vals.forEach((v,i)=>{if(v==null){started=false;return}d+=(started?'L':'M')+x(i)+' '+y(v)+' ';started=true;});
    g+=`<path d="${d}" fill="none" stroke="${s.color}" stroke-width="2" ${s.dash?'stroke-dasharray="5 4"':''} stroke-linejoin="round"/>`;
    s.vals.forEach((v,i)=>{if(v!=null)g+=`<circle cx="${x(i)}" cy="${y(v)}" r="2.5" fill="${s.color}"/>`;});
  });
  // hover 层
  g+=`<rect x="${pl}" y="${pt}" width="${W-pl-pr}" height="${H-pt-pb}" fill="transparent" class="hov"/></svg>`;
  const box=document.createElement('div'); box.className='chartbox'; box.innerHTML=g;
  const svg=box.querySelector('svg');
  svg.querySelector('.hov').addEventListener('mousemove',e=>{
    const r=svg.getBoundingClientRect(), sx=(e.clientX-r.left)*(W/r.width);
    let i=Math.round((sx-pl)/((W-pl-pr)/(cfg.labels.length-1||1))); i=Math.max(0,Math.min(cfg.labels.length-1,i));
    let h=`<b>${cfg.labels[i]}</b>`;
    cfg.series.forEach(s=>{if(s.vals[i]!=null)h+=`<br><span style="color:${s.color}">■</span> ${s.name}: ${cfg.tfmt?cfg.tfmt(s.vals[i]):cfg.yfmt(s.vals[i])}`;});
    TT.innerHTML=h; TT.style.opacity=1; TT.style.left=(e.clientX+12)+'px'; TT.style.top=(e.clientY+12)+'px';
  });
  svg.querySelector('.hov').addEventListener('mouseleave',()=>TT.style.opacity=0);
  return box;
}
// 把 18 月序列拆成 2025(Jan-Dec) 与 2026(Jan-Jun),按日历月对齐叠放
function calYo(vals){const y25=[],y26=[];for(let i=0;i<12;i++)y25.push(vals[i]);for(let i=12;i<18;i++)y26.push(vals[i]);while(y26.length<12)y26.push(null);return{y25,y26};}
const MLAB=['1月','2月','3月','4月','5月','6月','7月','8月','9月','10月','11月','12月'];

function el(t,c,h){const e=document.createElement(t);if(c)e.className=c;if(h!=null)e.innerHTML=h;return e;}
function kpiCard(lab,val,note,klass){return `<div class="card kpi"><div class="lab">${lab}</div><div class="val ${klass||''}">${val}</div><div class="note">${note||''}</div></div>`;}

// ============ TAB 0 概览 ============
function tab0(){
  const p=document.getElementById('p0'); let h='';
  const k=KPI;
  h+='<h2>核心结论</h2>';
  h+=`<div class="ins"><b>① 你其实在增长,但不够快。</b> 美亚 H1 销售额 ${money(k.h1_25)} → <b>${money(k.h1_26)}</b>(同比 <span class="up">+${k.h1_yoy}%</span>),并非"没增量"。但全年 US 目标 ${cny(k.tlo_cny/FX)}–${cny(k.thi_cny/FX)}(¥1.95–2.1亿)要求全年 <b>+${k.req_yoy_lo}%~+${k.req_yoy_hi}%</b>,现增速远不够。</div>`;
  h+=`<div class="ins an watch"><b>② 按季节性外推,全年约 ${money(k.proj_fy26)}(${cny(k.proj_fy26)}),缺口 ${money(-k.gap_hi)}–${money(-k.gap_lo)}(¥${(-k.gap_hi*FX/1e6).toFixed(0)}–${(-k.gap_lo*FX/1e6).toFixed(0)}M),差 ${(100-k.proj_fy26/k.tlo*100).toFixed(0)}–${(100-k.proj_fy26/k.thi*100).toFixed(0)}%。</b> H1 仅占全年 ${k.share_h1}%,而 Nov+Dec 占 <b>${k.q4_share}%</b> —— 增量是一场 <b>Q4 决战</b>,现在(7月)正是布局窗口。要达标,H2 需同比 <b>+${k.h2_yoy_lo}%~+${k.h2_yoy_hi}%</b>。</div>`;
  h+=`<div class="ins an"><b>③ 增长质量在恶化(焦虑的真正来源)。</b> H1 订单 <span class="up">+${k.o_yoy}%</span> 却只换来营收 +${k.h1_yoy}% → 实际客单价 $${k.aov_25}→$${k.aov_26}(<span class="down">${k.aov_yoy}%</span>)。<b>list 价在涨(内存倒逼),真实到手价却在跌</b>:增量靠新低价品 1035($250)+ 旗舰 1032 大促(占其营收~40%)换来,不是靠涨价。两个老品 1004/1002 销量同比 -6~7%,以价换量地萎缩。</div>`;
  h+=`<div class="ins good"><b>④ 但基本盘在变强。</b> Ikarao 在卡拉OK品类的<b>购买份额从 2.4%→4.8%(翻倍)</b>,曝光→购买的转化漏斗漏损减半——品牌力/评论在把高价单转化出来。头部词 <code>karaoke machine for adults</code> 购买份额 5.5%(是通用词的2倍),"adults/premium"就是 Ikarao 的护城河。</div>`;

  h+='<h2>目标缺口(美亚 US)</h2><div class="grid k4">';
  h+=kpiCard('H1 2026 销售额',money(k.h1_26),`同比 +${k.h1_yoy}% · ${cny(k.h1_26)}`,'');
  h+=kpiCard('FY2025 实际',money(k.fy25),`${cny(k.fy25)} · 基数`,'');
  h+=kpiCard('外推 FY2026',money(k.proj_fy26),`${cny(k.proj_fy26)} · 按季节性`,'warnc');
  h+=kpiCard('US 目标',`${cny(k.tlo_cny/FX)}~${cny(k.thi_cny/FX)}`,`需全年+${k.req_yoy_lo}~${k.req_yoy_hi}%`,'');
  h+='</div>';
  h+=`<div class="card" style="margin-top:12px"><h3>全年达标路径</h3><div id="pathchart"></div><div class="sm mut">灰虚线=2025各月实际;蓝线=2026实际(至6月);阴影提示 Q4 是决胜期。达标要求 H2(7-12月)做到 ${money(k.h2_need_lo)}~${money(k.h2_need_hi)},即比去年 H2(${money(k.h2_25)})再 +${k.h2_yoy_lo}~${k.h2_yoy_hi}%。</div></div>`;

  h+='<h2>增长来源拆解(H1 同比)</h2>';
  h+='<div class="card"><table id="srctbl"></table></div>';
  p.innerHTML=h;
  // 路径图
  const st=calYo(DATA.store.sales);
  document.getElementById('pathchart').appendChild(lineChart({labels:MLAB,series:[
    {name:'2025',color:'#94a3b8',vals:st.y25,dash:true},{name:'2026',color:'#2563eb',vals:st.y26}],
    yfmt:money,zero:true,h:230}));
  // 来源表
  srcTable();
}
function srcTable(){
  const idx1=[0,1,2,3,4,5], idx2=[12,13,14,15,16,17];
  const rowsH=['款型','H1 2025','H1 2026','同比额','H1 25销量','H1 26销量','同比量'];
  let t='<thead><tr>'+rowsH.map((x,i)=>`<th class="${i?'r':''}">${x}</th>`).join('')+'</tr></thead><tbody>';
  let tot25=0,tot26=0,v25=0,v26=0;
  DATA.order.forEach(a=>{
    const A=DATA.asins.find(z=>z.asin===a);
    const s25=idx1.reduce((p,i)=>p+(A.s.amount[i]||0),0), s26=idx2.reduce((p,i)=>p+(A.s.amount[i]||0),0);
    const q25=idx1.reduce((p,i)=>p+(A.s.volume[i]||0),0), q26=idx2.reduce((p,i)=>p+(A.s.volume[i]||0),0);
    tot25+=s25;tot26+=s26;v25+=q25;v26+=q26;
    const ay=s25?((s26/s25-1)*100):null, vy=q25?((q26/q25-1)*100):null;
    t+=`<tr><td><b style="color:${A.color}">${A.model}</b></td><td>${money(s25)}</td><td>${money(s26)}</td><td class="${cls(ay)}">${ay==null?'新品':sign(ay)+ay.toFixed(0)+'%'}</td><td>${intf(q25)}</td><td>${intf(q26)}</td><td class="${cls(vy)}">${vy==null?'新品':sign(vy)+vy.toFixed(0)+'%'}</td></tr>`;
  });
  const ay=(tot26/tot25-1)*100, vy=(v26/v25-1)*100;
  t+=`<tr style="font-weight:700;border-top:2px solid #cbd5e1"><td>5款合计</td><td>${money(tot25)}</td><td>${money(tot26)}</td><td class="${cls(ay)}">+${ay.toFixed(0)}%</td><td>${intf(v25)}</td><td>${intf(v26)}</td><td class="${cls(vy)}">+${vy.toFixed(0)}%</td></tr>`;
  t+=`<tr class="mut"><td>全店(含长尾)</td><td>${money(KPI.h1_25)}</td><td>${money(KPI.h1_26)}</td><td class="up">+${KPI.h1_yoy}%</td><td>${intf(KPI.o_h1_25)}</td><td>${intf(KPI.o_h1_26)}</td><td class="up">+${KPI.o_yoy}%</td></tr>`;
  t+='</tbody>';
  document.getElementById('srctbl').innerHTML=t;
}

// ============ TAB 1 品牌趋势 ============
const METRICS=[
 {k:'amount',n:'销售额',f:money,agg:'sum'},{k:'volume',n:'销量',f:intf,agg:'sum'},
 {k:'asp',n:'实际客单价',f:v=>'$'+(v==null?'—':v.toFixed(0)),agg:'calc'},
 {k:'sessions',n:'会话(流量)',f:intf,agg:'sum'},
 {k:'adv_rate',n:'广告销售占比',f:pct100,agg:'calc'},
];
let mSel='amount', mMode='cal';
function tab1(){
  const p=document.getElementById('p1');
  p.innerHTML=`<h2>品牌/全店 月度趋势</h2>
  <div class="ctrls"><span class="sm mut">指标:</span><span id="mbtns"></span></div>
  <div class="ctrls"><span class="sm mut">视图:</span>
   <span class="btn ${mMode=='cal'?'on':''}" data-md="cal">同比叠放(25vs26)</span>
   <span class="btn ${mMode=='mom'?'on':''}" data-md="mom">环比%</span>
   <span class="btn ${mMode=='abs'?'on':''}" data-md="abs">18月连续</span></div>
  <div class="card"><div id="bchart"></div><div class="lgd" id="blgd"></div></div>
  <div class="card" style="margin-top:12px"><h3>全店 vs 5款合计(销售额)</h3><div id="bchart2"></div></div>`;
  document.getElementById('mbtns').innerHTML=METRICS.map(m=>`<span class="btn ${m.k==mSel?'on':''}" data-m="${m.k}">${m.n}</span>`).join('');
  p.querySelectorAll('[data-m]').forEach(b=>b.onclick=()=>{mSel=b.dataset.m;tab1();});
  p.querySelectorAll('[data-md]').forEach(b=>b.onclick=()=>{mMode=b.dataset.md;tab1();});
  const met=METRICS.find(m=>m.k==mSel);
  const vals=DATA.brand[mSel]||[];
  const box=document.getElementById('bchart');
  if(mMode=='cal'){const yo=calYo(vals);
    box.appendChild(lineChart({labels:MLAB,series:[{name:'2025',color:'#94a3b8',vals:yo.y25,dash:true},{name:'2026',color:'#2563eb',vals:yo.y26}],yfmt:met.f,zero:met.agg=='sum'}));
    document.getElementById('blgd').innerHTML='<span><i class="dot" style="background:#94a3b8"></i>2025</span><span><i class="dot" style="background:#2563eb"></i>2026</span>';
  }else if(mMode=='mom'){const mm=[];for(let i=1;i<vals.length;i++){const a=vals[i],b=vals[i-1];mm.push(a!=null&&b?((a/b-1)*100):null);}
