    const ad=mean3(A.s.adv_rate);t+=`<td class="${ad>=0.82?'down':''}">${pct100(ad)}</td>`;
    t+=`<td>${pct100(mean3(A.s.tacos))}</td>`;
    const ps=mean3(A.s.promo_share);t+=`<td class="${ps>=0.28?'down':''}">${pct100(ps)}</td>`;
    const rk=A.s.rank_k.filter(v=>v!=null).slice(-1)[0];t+=`<td>${rk?'#'+Math.round(rk):'—'}</td>`;
    t+='</tr>';});
  t+='</tbody>';box.querySelector('#cmp').innerHTML=t;
}

// ============ TAB 3 关键词 ============
let kwView='brand';
function tab3(){
  const p=document.getElementById('p3');
  p.innerHTML=`<h2>关键词洞察(搜索查询绩效 SQP)</h2>
