     <input id="kwq" placeholder="过滤关键词…" style="margin-bottom:8px;width:220px"><div class="chartbox"><table id="kwtbl"></table></div></div>`;
  p.querySelectorAll('[data-v]').forEach(b=>b.onclick=()=>{kwView=b.dataset.v;tab3();});
