let kwSort={k:'sv',dir:-1};
function buildKwTable(D,li,q){
  const rows=D.table.map(r=>({kw:r.kw,branded:r.branded,sv:r.sv[li],impr:r.impr_share[li],purch:r.purch_share[li],conv:r.conv[li],
     pm:r.price_mkt[li]||null,pmine:r.price_mine[li]||null})).filter(r=>!q||r.kw.toLowerCase().includes(q));
  rows.sort((a,b)=>{const x=a[kwSort.k],y=b[kwSort.k];return ((x==null?-1:x)-(y==null?-1:y))*kwSort.dir;});
  const cols=[['关键词','kw'],['搜索量','sv'],['曝光份','impr'],['购买份','purch'],['你转化','conv'],['市场价','pm'],['你的价','pmine']];
  let t='<thead><tr>'+cols.map((c,i)=>`<th class="${i?'r':''}" data-s="${c[1]}">${c[0]}</th>`).join('')+'</tr></thead><tbody>';
  rows.slice(0,120).forEach(r=>{t+=`<tr><td>${r.kw}${r.branded?' <span class="tag">品牌</span>':''}</td><td>${intf(r.sv)}</td><td>${r.impr==null?'—':r.impr+'%'}</td><td>${r.purch==null?'—':r.purch+'%'}</td><td>${r.conv==null?'—':r.conv+'%'}</td><td>${r.pm?'$'+r.pm:'—'}</td><td>${r.pmine?'$'+r.pmine:'—'}</td></tr>`;});
  t+='</tbody>';const T=document.getElementById('kwtbl');T.innerHTML=t;
  T.querySelectorAll('[data-s]').forEach(th=>th.onclick=()=>{const k=th.dataset.s;kwSort.dir=(kwSort.k==k?-kwSort.dir:-1);kwSort.k=k;buildKwTable(D,li,q);});
}

