// 暴露tab函数以便逐个测试
script+='\n;globalThis.__tabs=[tab0,tab1,tab2,tab3,tab4];globalThis.__show=show;';

function makeNode(){
  const t=function(){return makeNode();};
  return new Proxy(t,{
    get(o,p){
      switch(p){
        case 'innerHTML': return o._html||'';
        case 'style': return o._style||(o._style=makeNode());
        case 'classList': return {toggle(){},add(){},remove(){},contains(){return false}};
        case 'dataset': return o._ds||(o._ds={i:'0',m:'amount',md:'cal',v:'brand',s:'sv'});
        case 'appendChild': return (c)=>c;
        case 'setAttribute': return ()=>{};
        case 'addEventListener': return ()=>{};
        case 'removeEventListener': return ()=>{};
        case 'querySelector': return ()=>makeNode();
        case 'querySelectorAll': return ()=>[];
        case 'getBoundingClientRect': return ()=>({left:0,top:0,width:800,height:240});
        case 'value': return '';
        case 'forEach': return Array.prototype.forEach.bind([]);
        case Symbol.toPrimitive: return ()=>'';
        default: return makeNode();
      }
    },
    set(o,p,v){o['_'+String(p)]=v;return true;},
    apply(){return makeNode();}
  });
}
const doc={getElementById:()=>makeNode(),createElement:()=>makeNode(),
  querySelectorAll:()=>[],querySelector:()=>makeNode(),body:makeNode()};
